/**
 * Template for generating Fastify plugin files
 */

import { toPascalCase, toCamelCase } from '../../generators/utils.js';

export { generatePluginTestTemplate } from './plugin-test.template.js';

export function generatePluginTemplate(pluginName: string): string {
  const pascalName = toPascalCase(pluginName);
  const camelName = toCamelCase(pluginName);

  return `/**
 * @generated by @flusk/cli
 * ${pascalName} Plugin
 */

import fp from 'fastify-plugin';
import { FastifyInstance, FastifyPluginOptions } from 'fastify';

export interface ${pascalName}PluginOptions extends FastifyPluginOptions {
  // Add plugin configuration options here
  prefix?: string;
}

/**
 * ${pascalName} Fastify Plugin
 *
 * Usage:
 * \`\`\`typescript
 * // Register plugin:
 * await fastify.register(${camelName}Plugin, {
 *   prefix: '/api'
 * });
 * \`\`\`
 */
async function ${camelName}PluginImplementation(
  fastify: FastifyInstance,
  options: ${pascalName}PluginOptions
) {
  const { prefix = '' } = options;

  // Add routes
  fastify.get(\`\${prefix}/health\`, async (request, reply) => {
    return { status: 'ok', plugin: '${pluginName}' };
  });

  // Add hooks
  fastify.addHook('onRequest', async (request, reply) => {
    request.log.debug('${pascalName} plugin hook executed');
  });

  // Decorate Fastify instance
  fastify.decorate('${camelName}', {
    // Add plugin-specific functionality
    getName: () => '${pluginName}'
  });
}

/**
 * Export plugin with fastify-plugin wrapper for encapsulation
 */
export const ${camelName}Plugin = fp(${camelName}PluginImplementation, {
  fastify: '5.x',
  name: '${pluginName}-plugin'
});

// Type augmentation for TypeScript
declare module 'fastify' {
  interface FastifyInstance {
    ${camelName}: {
      getName(): string;
    };
  }
}
`;
}
